package com.zhengding.cloud.common.config.pool.fork;

import lombok.Data;
import lombok.extern.slf4j.Slf4j;
import net.dreamlu.mica.core.utils.BeanUtil;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.boot.test.context.SpringBootTest;

import java.util.*;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ForkJoinPool;
import java.util.concurrent.TimeUnit;
import java.util.function.Supplier;
import java.util.stream.Collectors;
import java.util.stream.IntStream;

/**
 * BeanUtils 性能优化与 var 重构测试用例
 *
 * 测试内容：
 * 1. BeanUtils.copyProperties vs Mica BeanUtil 性能对比
 * 2. var 变量定义优化
 * 3. 并行流处理大数据量
 * 4. 自定义 16 线程 ForkJoinPool 使用
 *
 * @author test
 */
@Slf4j
@SpringBootTest
public class BeanUtilsOptimizationTest {

    @Autowired
    @Qualifier("forkJoinPool16")
    private ForkJoinPool forkJoinPool16;

    @Autowired
    @Qualifier("forkJoinPool16Async")
    private ForkJoinPool forkJoinPool16Async;

    // ==================== 测试数据类 ====================

    @Data
    public static class SourceDTO {
        private Long id;
        private String name;
        private String email;
        private Integer age;
        private String address;
        private String phone;
        private Double salary;
        private Date createTime;
    }

    @Data
    public static class TargetVO {
        private Long id;
        private String name;
        private String email;
        private Integer age;
        private String address;
        private String phone;
        private Double salary;
        private Date createTime;
    }

    // ==================== 1. BeanUtils 性能对比测试 ====================

    /**
     * 测试 1.1: Spring BeanUtils vs Mica BeanUtil 性能对比
     */
    @Test
    public void testBeanUtilsPerformanceComparison() {
        log.info("=== 测试 1.1: BeanUtils 性能对比 ===");

        SourceDTO source = createSourceDTO();
        int iterations = 10000;

        // 测试 Spring BeanUtils
        long springStartTime = System.nanoTime();
        for (int i = 0; i < iterations; i++) {
            TargetVO target = new TargetVO();
            org.springframework.beans.BeanUtils.copyProperties(source, target);
        }
        long springEndTime = System.nanoTime();

        // 测试 Mica BeanUtil
        long micaStartTime = System.nanoTime();
        for (int i = 0; i < iterations; i++) {
            TargetVO target = BeanUtil.copyProperties(source, TargetVO.class);
        }
        long micaEndTime = System.nanoTime();

        double springMs = (springEndTime - springStartTime) / 1_000_000.0;
        double micaMs = (micaEndTime - micaStartTime) / 1_000_000.0;

        log.info("Spring BeanUtils: {} ms ({} 次迭代)", String.format("%.2f", springMs), iterations);
        log.info("Mica BeanUtil: {} ms ({} 次迭代)", String.format("%.2f", micaMs), iterations);
        log.info("性能提升：{}%", String.format("%.2f", ((springMs - micaMs) / springMs) * 100));
    }

    /**
     * 测试 1.2: 批量对象转换性能对比
     */
    @Test
    public void testBatchConversionPerformance() {
        log.info("=== 测试 1.2: 批量对象转换性能对比 ===");

        var sourceList = IntStream.range(0, 1000)
                .mapToObj(i -> createSourceDTO())
                .collect(Collectors.toList());

        // 传统方式
        long traditionalStart = System.nanoTime();
        var traditionalResult = sourceList.stream()
                .map(source -> {
                    var target = new TargetVO();
                    org.springframework.beans.BeanUtils.copyProperties(source, target);
                    return target;
                })
                .collect(Collectors.toList());
        long traditionalEnd = System.nanoTime();

        // Mica BeanUtil 方式
        long micaStart = System.nanoTime();
        var micaResult = sourceList.stream()
                .map(source -> BeanUtil.copyProperties(source, TargetVO.class))
                .collect(Collectors.toList());
        long micaEnd = System.nanoTime();

        double traditionalMs = (traditionalEnd - traditionalStart) / 1_000_000.0;
        double micaMs = (micaEnd - micaStart) / 1_000_000.0;

        log.info("传统方式：{} ms", String.format("%.2f", traditionalMs));
        log.info("Mica BeanUtil: {} ms", String.format("%.2f", micaMs));
        log.info("批量转换提升：{}%", String.format("%.2f", ((traditionalMs - micaMs) / traditionalMs) * 100));
        log.info("转换结果数量：{}", micaResult.size());
    }

    // ==================== 2. var 变量定义优化测试 ====================

    /**
     * 测试 2.1: 使用 var 简化代码 - 循环内创建对象优化
     */
    @Test
    public void testVarInLoopOptimization() {
        log.info("=== 测试 2.1: var 在循环中的使用 ===");

        var items = Arrays.asList("item1", "item2", "item3", "item4", "item5");

        // 优化前：每次循环都创建新的 HashMap
        var traditionalResult = new ArrayList<Map<String, Object>>();
        for (String item : items) {
            var map = new HashMap<String, Object>();
            map.put("key", item);
            map.put("timestamp", System.currentTimeMillis());
            traditionalResult.add(map);
        }

        // 优化后：使用 Stream API
        var streamResult = items.stream()
                .map(item -> {
                    var map = new HashMap<String, Object>();
                    map.put("key", item);
                    map.put("timestamp", System.currentTimeMillis());
                    return map;
                })
                .collect(Collectors.toList());

        log.info("传统方式结果数量：{}", traditionalResult.size());
        log.info("Stream 方式结果数量：{}", streamResult.size());
    }

    /**
     * 测试 2.2: 使用 Stream API 优化条件过滤
     */
    @Test
    public void testStreamFilterOptimization() {
        log.info("=== 测试 2.2: Stream API 条件过滤优化 ===");

        var items = Arrays.asList("apple", null, "banana", "", "cherry", "date", null);

        // 优化前：传统 for 循环
        var traditionalResult = new ArrayList<String>();
        for (String item : items) {
            if (item != null && !item.isEmpty()) {
                traditionalResult.add(item.toUpperCase());
            }
        }

        // 优化后：Stream API
        var streamResult = items.stream()
                .filter(Objects::nonNull)
                .filter(item -> !item.isEmpty())
                .map(String::toUpperCase)
                .collect(Collectors.toList());

        log.info("传统方式结果：{}", traditionalResult);
        log.info("Stream 方式结果：{}", streamResult);
    }

    /**
     * 测试 2.3: var 在集合操作中的使用
     */
    @Test
    public void testVarInCollectionOperations() {
        log.info("=== 测试 2.3: var 在集合操作中的使用 ===");

        // package lombok.var; 的 var 用法演示
        var body = new HashMap<String, Object>();
        body.put("userId", 12345L);
        body.put("userName", "testUser");
        body.put("roles", Arrays.asList("ADMIN", "USER"));

        var config = new HashMap<String, String>();
        config.put("env", "dev");
        config.put("version", "1.0.0");

        log.info("body: {}", body);
        log.info("config: {}", config);
    }

    // ==================== 3. 并行流处理大数据量测试 ====================

    /**
     * 测试 3.1: 并行流 vs 串行流性能对比
     */
    @Test
    public void testParallelStreamPerformance() {
        log.info("=== 测试 3.1: 并行流性能对比 ===");

        var largeDataList = IntStream.range(0, 10000)
                .mapToObj(i -> createSourceDTO())
                .collect(Collectors.toList());

        // 串行流处理
        long sequentialStart = System.nanoTime();
        var sequentialResult = largeDataList.stream()
                .map(this::processItem)
                .collect(Collectors.toList());
        long sequentialEnd = System.nanoTime();

        // 并行流处理
        long parallelStart = System.nanoTime();
        var parallelResult = largeDataList.parallelStream()
                .map(this::processItem)
                .collect(Collectors.toList());
        long parallelEnd = System.nanoTime();

        double sequentialMs = (sequentialEnd - sequentialStart) / 1_000_000.0;
        double parallelMs = (parallelEnd - parallelStart) / 1_000_000.0;

        log.info("串行流耗时：{} ms", String.format("%.2f", sequentialMs));
        log.info("并行流耗时：{} ms", String.format("%.2f", parallelMs));
        log.info("性能提升：{}%", String.format("%.2f", ((sequentialMs - parallelMs) / sequentialMs) * 100));
        log.info("结果数量验证：串行={}, 并行={}", sequentialResult.size(), parallelResult.size());
    }

    /**
     * 测试 3.2: 并行流处理 CPU 密集型计算
     */
    @Test
    public void testParallelStreamForCPUBoundTask() {
        log.info("=== 测试 3.2: 并行流处理 CPU 密集型计算 ===");

        var numbers = IntStream.range(1, 10000).boxed().collect(Collectors.toList());

        // 串行计算
        long seqStart = System.nanoTime();
        var seqResult = numbers.stream()
                .map(this::computeFibonacci)
                .collect(Collectors.toList());
        long seqEnd = System.nanoTime();

        // 并行计算
        long parStart = System.nanoTime();
        var parResult = numbers.parallelStream()
                .map(this::computeFibonacci)
                .collect(Collectors.toList());
        long parEnd = System.nanoTime();

        log.info("串行计算耗时：{} ms", String.format("%.2f", (seqEnd - seqStart) / 1_000_000.0));
        log.info("并行计算耗时：{} ms", String.format("%.2f", (parEnd - parStart) / 1_000_000.0));
        log.info("结果验证通过：{}", seqResult.equals(parResult));
    }

    // ==================== 4. 自定义 16 线程 ForkJoinPool 测试 ====================

    /**
     * 测试 4.1: 使用自定义 ForkJoinPool 执行异步任务
     */
    @Test
    public void testCustomForkJoinPoolExecute() throws Exception {
        log.info("=== 测试 4.1: 自定义 ForkJoinPool 执行任务 ===");

        var taskCompleted = new boolean[]{false};
        var taskResult = new String[1];

        // 使用注入的 16 线程池执行任务
        forkJoinPool16.execute(() -> {
            try {
                log.info("任务执行中，线程：{}", Thread.currentThread().getName());
                TimeUnit.MILLISECONDS.sleep(100);
                taskResult[0] = "Task Completed";
                taskCompleted[0] = true;
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        });

        // 等待任务完成
        TimeUnit.SECONDS.sleep(1);

        log.info("任务完成状态：{}", taskCompleted[0]);
        log.info("任务结果：{}", taskResult[0]);
    }

    /**
     * 测试 4.2: 使用 CompletableFuture 与自定义线程池
     */
    @Test
    public void testCompletableFutureWithCustomPool() throws Exception {
        log.info("=== 测试 4.2: CompletableFuture + 自定义线程池 ===");

        // 使用自定义 16 线程池
        var future = CompletableFuture.supplyAsync(() -> {
            log.info("处理数据，线程：{}", Thread.currentThread().getName());
            return processData();
        }, forkJoinPool16);

        var result = future.get();
        log.info("处理结果：{}", result);
    }

    /**
     * 测试 4.3: 批量异步任务处理
     */
    @Test
    public void testBatchAsyncTasks() throws Exception {
        log.info("=== 测试 4.3: 批量异步任务处理 ===");

        var tasks = IntStream.range(0, 20)
                .mapToObj(i -> CompletableFuture.supplyAsync(() -> {
                    log.info("任务{}执行，线程：{}", i, Thread.currentThread().getName());
                    return processHeavyTask(i);
                }, forkJoinPool16))
                .collect(Collectors.toList());

        // 等待所有任务完成
        var results = CompletableFuture.allOf(tasks.toArray(new CompletableFuture[0]))
                .thenApply(v -> tasks.stream()
                        .map(CompletableFuture::join)
                        .collect(Collectors.toList()))
                .get();

        log.info("所有任务完成，结果数量：{}", results.size());
        log.info("结果摘要：{}", results.stream().limit(5).collect(Collectors.toList()));
    }

    /**
     * 测试 4.4: 异步模式 ForkJoinPool 测试
     */
    @Test
    public void testAsyncForkJoinPool() throws Exception {
        log.info("=== 测试 4.4: 异步模式 ForkJoinPool 测试 ===");

        // 使用 FIFO_QUEUE 模式的线程池
        var future = CompletableFuture.supplyAsync(() -> {
            log.info("异步任务执行，线程：{}", Thread.currentThread().getName());
            return "Async Result";
        }, forkJoinPool16Async);

        var result = future.get();
        log.info("异步任务结果：{}", result);
    }

    // ==================== 5. 综合性能测试 ====================

    /**
     * 测试 5.1: 综合性能测试 - 结合所有优化技术
     */
    @Test
    public void testComprehensiveOptimization() throws Exception {
        log.info("=== 测试 5.1: 综合性能测试 ===");

        var sourceList = IntStream.range(0, 5000)
                .mapToObj(i -> createSourceDTO())
                .collect(Collectors.toList());

        // 方式 1: 传统方式
        long traditionalStart = System.nanoTime();
        var traditionalResult = processTraditionally(sourceList);
        long traditionalEnd = System.nanoTime();

        // 方式 2: 优化方式 (Mica BeanUtil + 并行流 + 自定义线程池)
        long optimizedStart = System.nanoTime();
        var optimizedResult = processOptimized(sourceList);
        long optimizedEnd = System.nanoTime();

        double traditionalMs = (traditionalEnd - traditionalStart) / 1_000_000.0;
        double optimizedMs = (optimizedEnd - optimizedStart) / 1_000_000.0;

        log.info("传统方式耗时：{} ms", String.format("%.2f", traditionalMs));
        log.info("优化方式耗时：{} ms", String.format("%.2f", optimizedMs));
        log.info("综合性能提升：{}%", String.format("%.2f", ((traditionalMs - optimizedMs) / traditionalMs) * 100));
        log.info("结果验证：传统={}, 优化={}", traditionalResult.size(), optimizedResult.size());
    }

    // ==================== 辅助方法 ====================

    private SourceDTO createSourceDTO() {
        var dto = new SourceDTO();
        dto.setId(System.nanoTime());
        dto.setName("Test User " + System.nanoTime());
        dto.setEmail("test@example.com");
        dto.setAge(25);
        dto.setAddress("Test Address");
        dto.setPhone("1234567890");
        dto.setSalary(50000.0);
        dto.setCreateTime(new Date());
        return dto;
    }

    private TargetVO processItem(SourceDTO source) {
        // 模拟一些处理逻辑
        var target = BeanUtil.copyProperties(source, TargetVO.class);
        // CPU 密集型操作
        double result = 0;
        for (int i = 0; i < 100; i++) {
            result += Math.sqrt(i);
        }
        target.setSalary(target.getSalary() + result);
        return target;
    }

    private int computeFibonacci(int n) {
        if (n <= 1) return n;
        return computeFibonacci(n - 1) + computeFibonacci(n - 2);
    }

    private String processData() {
        try {
            TimeUnit.MILLISECONDS.sleep(50);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        return "Processed Data";
    }

    private String processHeavyTask(int index) {
        try {
            TimeUnit.MILLISECONDS.sleep(10);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        return "Result-" + index;
    }

    private List<TargetVO> processTraditionally(List<SourceDTO> sourceList) {
        var result = new ArrayList<TargetVO>();
        for (SourceDTO source : sourceList) {
            var target = new TargetVO();
            org.springframework.beans.BeanUtils.copyProperties(source, target);
            result.add(target);
        }
        return result;
    }

    private List<TargetVO> processOptimized(List<SourceDTO> sourceList) {
        return sourceList.parallelStream()
                .map(source -> BeanUtil.copyProperties(source, TargetVO.class))
                .collect(Collectors.toList());
    }
}

