    /**
     * 测试 5.1: 综合性能测试 - 结合所有优化技术
     */
    @Test
    public void testComprehensiveOptimization() throws Exception {
        log.info("=== 测试 5.1: 综合性能测试 ===");

        var sourceList = IntStream.range(0, 5000)
                .mapToObj(i -> createSourceDTO())
                .collect(Collectors.toList());

