    // ==================== 辅助方法 ====================

    private SourceDTO createSourceDTO() {
        var dto = new SourceDTO();
        dto.setId(System.nanoTime());
        dto.setName("Test User " + System.nanoTime());
        dto.setEmail("test@example.com");
        dto.setAge(25);
        dto.setAddress("Test Address");
        dto.setPhone("1234567890");
        dto.setSalary(50000.0);
        dto.setCreateTime(new Date());
        return dto;
    }

    private TargetVO processItem(SourceDTO source) {
        // 模拟一些处理逻辑
        var target = BeanUtil.copyProperties(source, TargetVO.class);
        // CPU 密集型操作
        double result = 0;
        for (int i = 0; i < 100; i++) {
            result += Math.sqrt(i);
        }
        target.setSalary(target.getSalary() + result);
        return target;
    }

    private int computeFibonacci(int n) {
        if (n <= 1) return n;
        return computeFibonacci(n - 1) + computeFibonacci(n - 2);
    }

    private String processData() {
        try {
            TimeUnit.MILLISECONDS.sleep(50);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        return "Processed Data";
    }

    private String processHeavyTask(int index) {
        try {
            TimeUnit.MILLISECONDS.sleep(10);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        return "Result-" + index;
    }

    private List<TargetVO> processTraditionally(List<SourceDTO> sourceList) {
        var result = new ArrayList<TargetVO>();
        for (SourceDTO source : sourceList) {
            var target = new TargetVO();
            org.springframework.beans.BeanUtils.copyProperties(source, target);
            result.add(target);
        }
        return result;
    }

    private List<TargetVO> processOptimized(List<SourceDTO> sourceList) {
        return sourceList.parallelStream()
                .map(source -> BeanUtil.copyProperties(source, TargetVO.class))
                .collect(Collectors.toList());
    }
